import { BigDecimal } from '../../src/big-decimal';

// ================================================================
// Adversarial accuracy battery for the direct-log ln path
// (utils.ts: fplnDirect — machine-seed + log1p correction, folded √-reduced
// fpexp). fplnDirect replaced the giant_steps Newton kernel below the AGM
// threshold. It uses a ~48-bit float seed y0 = Math.log(v) and the correction
// log1p(v·e^{-y0} - 1) via a short atanh series. The danger zones it must hold
// across are: near-1 (the log1p argument's cancellation), tiny/huge decimal
// exponents (range reduction), and near-e (a common seed). This locks the
// result correctly-rounded across 15-500 digit precisions.
//
// References computed independently with mpmath (mp.dps = 540).
// ================================================================

const DEFAULT_PRECISION = 50;
beforeEach(() => {
  BigDecimal.precision = DEFAULT_PRECISION;
});
afterAll(() => {
  BigDecimal.precision = DEFAULT_PRECISION;
});

// mpmath ln(arg) to ~530 significant digits.
const REFS: Record<string, string> = {
  '1.0000000001':
    '0.',
  '0.9999999999':
    '-0.',
  '2.718281828459045':
    '0.',
  '1.5':
    '0.',
  '9.999':
    '2.',
  '7':
    '1.',
  '0.5':
    '-0.',
  '3':
    '1.',
  '1.0001':
    '0.',
  '2':
    '0.',
  '10':
    '2.',
  '0.1':
    '-2.',
  '123456.789':
    '11.',
  '1e-50':
    '-115.',
  '1e50':
    '115.',
};

/** Reference rounded to `p` significant digits. */
function refRounded(arg: string, p: number): BigDecimal {
  const saved = BigDecimal.precision;
  BigDecimal.precision = p;
  try {
    return new BigDecimal(REFS[arg]).toPrecision(p);
  } finally {
    BigDecimal.precision = saved;
  }
}

const PRECISIONS = [15, 21, 50, 100, 200, 500];

describe('ln direct-log: correctly rounded vs mpmath', () => {
  for (const arg of Object.keys(REFS)) {
    for (const p of PRECISIONS) {
      test(`ln(${arg}) @ ${p} digits`, () => {
        BigDecimal.precision = p;
        const got = new BigDecimal(arg).ln();
        const ref = refRounded(arg, p);
        const savedP = BigDecimal.precision;
        BigDecimal.precision = p + 5;
        const diff = got.sub(ref).abs();
        // 1 ulp at p significant digits, sized off the reference magnitude.
        const ulp = ref.abs().mul(new BigDecimal(`1e-${p - 1}`));
        BigDecimal.precision = savedP;
        expect(diff.lte(ulp)).toBe(true);
      });
    }
  }
});

describe('ln direct-log: cross-precision rounding stability', () => {
  // Computing at p+25 then rounding to p must equal computing at p directly.
  const args = ['1.0000000001', '2.718281828459045', '9.999', '0.5', '1e-50'];
  for (const arg of args) {
    for (const p of [21, 50, 100, 200]) {
      test(`ln(${arg}) @ ${p} == @ ${p + 25} rounded`, () => {
        BigDecimal.precision = p;
        const direct = new BigDecimal(arg).ln();
        BigDecimal.precision = p + 25;
        const wide = new BigDecimal(arg).ln();
        BigDecimal.precision = p;
        expect(wide.toPrecision(p).toString()).toBe(direct.toString());
      });
    }
  }
});

describe('ln direct-log: dense near-1 sweep (log1p cancellation zone)', () => {
  // x = 1 ± 10^-k densely: the near-1 region where the machine-seed correction's
  // atanh argument u -> 0. Compare against a wider-precision computation.
  const P = 60;
  for (let k = 1; k <= 30; k++) {
    for (const sign of ['+', '-']) {
      test(`ln(1${sign}1e-${k}) @ ${P}`, () => {
        const arg = `${sign === '+' ? '1.' + '0'.repeat(k - 1) + '1' : ''}`;
        // Build 1 ± 10^-k exactly.
        BigDecimal.precision = P + 40;
        const x =
          sign === '+'
            ? BigDecimal.ONE.add(new BigDecimal(`1e-${k}`))
            : BigDecimal.ONE.sub(new BigDecimal(`1e-${k}`));
        const wide = x.ln();
        BigDecimal.precision = P;
        const narrow = x.ln();
        const ref = wide.toPrecision(P);
        BigDecimal.precision = P + 5;
        const diff = narrow.sub(ref).abs();
        const ulp = ref.abs().mul(new BigDecimal(`1e-${P - 1}`));
        BigDecimal.precision = P;
        expect(diff.lte(ulp)).toBe(true);
        void arg;
      });
    }
  }
});
